/// Generated type representing the anonymous struct variant `WriteScale` of the `Command` Rust enum
@Serializable
data class CommandWriteScaleInner (
	/// The bytes to write.
	val data: List<UByte>
)

/// A BLE write the shell should perform on the core's behalf.
/// 
/// The core owns the protocol, so a command carries the exact bytes; the shell
/// only needs a characteristic-UUID map, no protocol logic.
@Serializable
sealed class Command {
	/// Write `data` to a DE1 GATT characteristic.
	@Serializable
	@SerialName("WriteCharacteristic")
	data class WriteCharacteristic(val content: CommandWriteCharacteristicInner): Command()
	/// Write `data` to the connected scale's command characteristic.
	@Serializable
	@SerialName("WriteScale")
	data class WriteScale(val content: CommandWriteScaleInner): Command()
}

/// The result of feeding the core one input: what it observed (`events`) and
/// what it wants the shell to do (`commands`).
/// 
/// `#[non_exhaustive]` so further fields can be added without breaking the
/// bridge crates.
@Serializable
data class CoreOutput (
	/// The events observed, in order.
	val events: List<Event>,
	/// BLE writes the shell should perform, in order.
	val commands: List<Command>
)

/// The DE1's GATT service + characteristic UUIDs (full lowercase 128-bit
/// strings). The shells scan on [`service`](Self::service), subscribe to the
/// notify characteristics, and address writes via [`de1_write_target_uuid`].
@Serializable
data class De1Uuids (
	/// GATT service (`A000`) — the scan filter.
	val service: String,
	/// `A001` Version — the BLE + firmware version block (read).
	val version: String,
	/// `A002` RequestedState — a 1-byte state request is written here.
	val requestedState: String,
	/// `A00B` ShotSettings — steam / hot-water settings (notify + write).
	val shotSettings: String,
	/// `A005` ReadFromMMR — a read request is written here; the DE1 answers on
	/// the same characteristic's notify.
	val mmrRead: String,
	/// `A006` WriteToMMR — an MMR write packet is sent here.
	val mmrWrite: String,
	/// `A00D` ShotSample — the ~4–10 Hz telemetry notify stream.
	val shotSample: String,
	/// `A00E` StateInfo — the 2-byte machine state + substate notify.
	val stateInfo: String,
	/// `A011` WaterLevels — the tank-level notify (also written to set the
	/// refill threshold).
	val waterLevels: String,
	/// `A012` Calibration — a read request is written here; the DE1 answers on
	/// the same characteristic's notify.
	val calibration: String,
	/// `A00F` HeaderWrite — the 5-byte profile-upload header (write).
	val headerWrite: String,
	/// `A010` FrameWrite — profile frame writes. The DE1 sends NO notification
	/// here (it only ACKs the ATT write) — the shell synthesizes a frame-ack.
	val frameWrite: String
)

/// Structured detector outputs — the typed values behind the prose lines,
/// mirroring Decenza's `DetectorResults` (`shotanalysis.h:479-600`).
/// `*_checked == false` means the detector was suppressed (pour-truncated
/// cascade, beverage-type skip, profile flag, or insufficient input); the
/// rest of that detector's fields stay at their defaults. Distinguishing
/// "not checked" from "checked, no signal" matters — silence on a skipped
/// detector is not the same as silence on a clean shot.
@Serializable
data class DetectorResults (
	/// Pour never pressurized — runs first and dominates the cascade.
	val pourTruncated: Boolean,
	/// Peak pour-window pressure; populated only when `pour_truncated` fired.
	val peakPressureBar: Double,
	/// Pour window start the cascade used (0 when no pour/preinfusion
	/// markers were present).
	val pourStartS: Double,
	/// Pour window end (shot duration when no "End" marker; 0 only on the
	/// insufficient-data early return).
	val pourEndS: Double,
	/// Whether the channeling detector ran.
	val channelingChecked: Boolean,
	/// "" if unchecked; else "none" / "transient" / "sustained".
	val channelingSeverity: String,
	/// Timestamp of the largest |dC/dt| spike inside the analysis windows.
	val channelingSpikeTimeS: Double,
	/// Whether the flow-trend detector ran.
	val flowTrendChecked: Boolean,
	/// "" if unchecked; else "stable" / "rising" / "falling".
	val flowTrend: String,
	/// (avg flow in last 30% of pour) − (avg in first 30%).
	val flowTrendDeltaMlS: Double,
	/// Preinfusion drip observation fired (weight and duration thresholds).
	val preinfusionObserved: Boolean,
	/// Cup weight at the end of preinfusion.
	val preinfusionDripWeightG: Double,
	/// Preinfusion duration (first marker → preinfusion end).
	val preinfusionDripDurationS: Double,
	/// Whether the grind detector ran (not suppressed by cascade or config).
	val grindChecked: Boolean,
	/// At least one grind arm produced a result.
	val grindHasData: Boolean,
	/// The pressure-mode choke check fired (severe flow or moderate yield
	/// arm).
	val grindChokedPuck: Boolean,
	/// Yield ran past target by more than [`YIELD_OVERSHOOT_RATIO_MIN`].
	val grindYieldOvershoot: Boolean,
	/// The puck behaved through a sustained pressurized pour — positive
	/// verification, not just absence of signal.
	val grindVerifiedClean: Boolean,
	/// (avg actual flow) − (avg goal flow); positive = coarse. Meaningful
	/// only when neither `grind_choked_puck` nor `grind_yield_overshoot`
	/// fired.
	val grindFlowDeltaMlS: Double,
	/// Qualifying samples averaged (Arm 1) or pressurized samples observed
	/// (choked path).
	val grindSampleCount: Int,
	/// "" if no data; else "yieldOvershoot" / "chokedPuck" / "tooFine" /
	/// "tooCoarse" / "onTarget".
	val grindDirection: String,
	/// "verified" / "notAnalyzable" / "skipped" / "" (pour-truncated cascade
	/// or degenerate pour window) — see `shotanalysis.h:556-573`.
	val grindCoverage: String,
	/// Profile frame 0 appears to have been skipped.
	val skipFirstFrame: Boolean
)

/// One profile frame's configured exit, used to infer
/// [`PhaseMarker::transition_reason`] for reconstructed markers (indexed by
/// frame number in [`ShotQualityInput::frame_exits`]).
/// 
/// Crema never stored live transition reasons — shells rebuild phase markers
/// from telemetry, so every reason arrived as `""` and the confirmed-exit
/// suppression in skip-first-frame detection was dead code: a fill frame
/// exiting early on its pressure target got a false "First step skipped"
/// badge on every shot (the exact user-visible symptom Decenza fixed in
/// PR #1421, `shotanalysis.cpp:677-699`). With the specs supplied, the
/// analysis infers the reason from the recorded series at each boundary.
@Serializable
data class FrameExitSpec (
	/// "pressure" / "flow", or "" when the frame has no early exit.
	val metric: String,
	/// True = the frame exits when the metric rises OVER the threshold;
	/// false = when it falls under.
	val exitOver: Boolean,
	/// Exit threshold (bar or mL/s, per `metric`).
	val threshold: Double,
	/// Configured max frame duration, seconds; `<= 0` when unknown.
	val maxDurationS: Double
)

/// A slim view onto the shell's `StoredShot`: only the fields the
/// reconcile planner reads. Lets the shell project its full record
/// (web `StoredShot` in `$lib/history/model.ts`, Android equivalent)
/// into a stable cross-shell shape without dragging the rest of the
/// record (`series`, `bean`, `metadata`) through the FFI.
/// 
/// Field names are camelCase on the wire — the JSON shape lines up
/// 1:1 with the web shell's `StoredShot`, so callers can hand a
