	val id: String,
	/// Roastery name. **Required.**
	val name: String,
	/// Roastery website / store URL.
	val website: String? = null,
	/// Logo / hero image URL. Mirrors Visualizer's `RoasterDetail.image_url`
	/// — round-trips losslessly on sync. Renders as a small thumbnail in
	/// the roaster card and the editor's preview slot.
	val imageUrl: String? = null,
	/// City — e.g. `"Portland"`. Crema-only; rides in `metadata.crema.city`
	/// on Visualizer round-trip so the wire format stays lossless.
	val city: String? = null,
	/// Country / state / region — free text. Crema-only.
	val country: String? = null,
	/// Free-form notes (private to the user — not pushed to Visualizer).
	val notes: String,
	/// Pointer to the canonical roaster id when this row was tagged as a
	/// duplicate. `None` = this row is itself canonical (or has not been
	/// deduped). Mirrors Visualizer's `RoasterDetail.canonical_roaster_id`
	/// — round-trips directly. Beans pointing at a duplicate are typically
	/// re-pointed at the canonical id on merge.
	val canonicalRoasterId: String? = null,
	/// Visualizer `roaster.id` once pushed.
	val visualizerId: String? = null,
	/// Unix epoch ms when this roaster was soft-deleted, or `None` when
	/// active. See [`Bean::deleted_at`] for the rationale. Defaults to
	/// `None` so older JSON deserialises cleanly.
	val deletedAt: Long? = null,
	/// Open JSON metadata — escape valve symmetric with [`Bean::metadata`].
	val metadata: kotlinx.serialization.json.JsonElement,
	/// Unix epoch ms.
	val createdAt: Long,
	/// Unix epoch ms.
	val updatedAt: Long
)

/// What a connected scale can do, beyond reporting a bare weight.
/// 
/// Crema is **capability-driven, never device-driven**: the app reads this
/// descriptor and conditionally enables features, so it never branches on a
/// concrete scale model. A plain weight-only scale has every field absent /
/// `false` / empty; a "first-class" scale (the Bookoo today) sets the
/// capabilities it supports.
/// 
/// Ranged settings carry their real `[min, max]` bounds as a
/// [`RangeCapability`] (`None` = the scale does not expose that setting), so
/// the shell renders a control over the actual range. Toggle settings stay a
/// plain `bool` — there is nothing to parameterize. The selectable display
/// modes are a `Vec<ModeInfo>` (empty = no mode support).
/// 
/// `#[non_exhaustive]`: more capabilities are added here as later slices land,
/// without breaking callers — a new field is purely additive.
@Serializable
data class ScaleCapabilities (
	/// The scale reports its own native mass-flow rate in its weight
	/// notification (surfaced as `ScaleReading::flow_g_per_s`).
	val reports_flow: Boolean,
	/// The scale reports its own built-in-timer reading in its weight
	/// notification (surfaced as `ScaleReading::timer_ms`).
	val reports_timer: Boolean,
	/// The bounds of the scale's settable beeper volume — `None` when the
	/// scale's volume is not settable. `min` is the quietest step (`0` =
	/// silent), `max` the loudest.
	val volume: RangeCapability? = null,
	/// The bounds of the scale's auto-standby timeout, in minutes — `None`
	/// when the scale has no configurable auto-standby.
	val standby: RangeCapability? = null,
	/// The scale accepts a command to toggle flow smoothing.
	val flow_smoothing: Boolean,
	/// The scale accepts a command to toggle anti-mistouch.
	val anti_mistouch: Boolean,
	/// The scale accepts a command to select its auto-stop mode (the Bookoo's
	/// flow-stop / cup-removal setting).
	val auto_stop: Boolean,
	/// The selectable display/behaviour modes the scale exposes — empty when
	/// the scale has no switchable modes. Each entry carries the mode's wire
	/// `id` and a display `name`.
	val modes: List<ModeInfo>,
	/// True when the scale's on-scale LCD is settable — drives the
	/// shell's "Enable on-scale LCD" toggle UI. Mirrors
	/// [`Scale::lcd_enable_command`] returning `Some`.
	val can_lcd: Boolean,
	/// True when the scale accepts a host-driven power-off command.
	/// Mirrors [`Scale::power_off_command`] returning `Some`.
	val can_power_off: Boolean,
	/// True when the scale accepts a beep command. Mirrors
	/// [`Scale::beep_command`] returning `Some`.
	val can_beep: Boolean,
	/// True when the scale exposes an explicit "set unit to grams"
	/// command (Eureka, Solo, Difluid). Mirrors
	/// [`Scale::set_unit_grams_command`] returning `Some`.
	val can_set_unit_grams: Boolean,
	/// True when the scale exposes a toggle-unit command (Hiroia).
	/// Mirrors [`Scale::toggle_unit_command`] returning `Some`.
	val can_toggle_unit: Boolean,
	/// Recommended cadence (milliseconds) between heartbeat writes when
	/// the scale needs periodic keep-alives — `Some(2000)` for the
	/// Decent Scale (keeps its on-scale LCD awake), `None` for every
	/// scale that does not. Mirrors [`Scale::heartbeat_command`]
	/// returning `Some`, with the cadence now living next to the bytes
	/// so the shell no longer carries a parallel constant.
	val heartbeat_interval_ms: UInt? = null
)

/// The BLE UUIDs a scale's transport layer needs.
/// 
/// `Clone` but not `Copy`: three string slices (48 bytes) exceed the size
/// where implicit copies are a sensible default.
/// 
/// `#[typeshare]` + serde `Serialize` (behind the `serde` feature): the web
/// shell needs these UUIDs to know which Web Bluetooth characteristics to
/// subscribe to, so they cross the JSON bridge boundary.
@Serializable
data class ScaleUuids (
	/// GATT service UUID.
	val service: String,
	/// Characteristic weight notifications arrive on.
	val weight_notify: String,
	/// Characteristic commands are written to — equal to `weight_notify` for
	/// scales that use a single characteristic for both.
	val command_write: String,
	/// Whether `command_write` ALSO delivers notifications, so the shell should
	/// subscribe to it (beyond `weight_notify`). True only for a scale whose
	/// command characteristic pushes data back — today just the Bookoo (`ff12`,
	/// its serial / settings frames). False for a write-only command
	/// characteristic: enabling notifications on one (e.g. the Decent's `36f5`)
	/// fails at the GATT layer and crashes the connect, so the shell must skip
	/// it. Capability-driven — the core, which owns the protocol, decides.
	val command_notifies: Boolean,
	/// A third characteristic that notifies on-scale button presses — today
	/// only the Skale II's `EF82` (de1app subscribes and logs it,
	/// `bluetooth.tcl:221`; Decenza emits `buttonPressed`). `None` for every
	/// other scale. The shell subscribes when present and forwards the bytes
	/// as `Source::ScaleButton`.
	val button_notify: String? = null,
	/// Whether `command_write` must be written WITHOUT response. True only
	/// for the gen-1/IPS Acaia — its command characteristic rejects
	/// with-response writes (Decenza acaiascale.cpp:279-295 "IPS and Pyxis
	/// require different write types"). Every other scale (incl. Pyxis)
	/// accepts the shells' default with-response write.
	val command_write_no_response: Boolean
)

/// One sample of a time series: `t` seconds from extraction start, `v` the
/// value (bar, mL/s, g, or conductance depending on the series). Series are
/// ordered ascending by `t`; there is no fixed sample rate — every window
/// rule works off the actual timestamps.
@Serializable
data class SeriesPoint (
	/// Seconds from extraction start.
	val t: Double,
	/// Sample value.
	val v: Double
)

/// A snapshot of the active bean at the moment a shot was pulled.
/// Frozen onto each [`crate::history::StoredShot`] (in the shell's
/// extended record) so a later rename / archive / delete of the bag
/// does not retroactively rewrite history.
/// 
/// Beanconqueror reads the bean *live* off the brew (`Brew.bean: uuid`,
/// see `Beanconqueror/src/classes/brew/brew.ts:60`). Crema takes the
/// other approach: snapshot wins. A shot recorded under "Onyx Geisha"
/// stays "Onyx Geisha" forever, even if the user later renames the bag.
/// 
/// Holds the strict minimum the History list / detail panel needs to
/// render the shot without re-fetching the bag — the user-facing
/// strings plus the dates that drive the freshness pill.
@Serializable
data class ShotBean (
	/// FK back to the [`Bean`] in the library, if it still exists. The
	/// History row can resolve the link to open the bean detail; an
	/// archived / deleted bean falls back to the snapshot strings.
	val beanId: String? = null,
	/// Bag name at the time of the shot — `"Geisha Esmeralda Lot 3"`.
	val name: String,
	/// Roaster name at the time of the shot. Not the roaster id — the
	/// id might dangle, but a string survives.
	val roasterName: String? = null,
	/// ISO `yyyy-mm-dd` roast date at the time of the shot.
	val roastedOn: String? = null,
	/// Roast level (1..10) at the time of the shot.
	val roastLevel: UByte? = null,
	/// The bean's tags at the time of the shot.
	val tags: List<String>? = null,
	/// Per-bean grinder setting at the time of the shot — distinct
	/// from the equipment-level `grinder_model` on [`StoredShot`]
	/// (the *machine* used) and `ShotMetadata::grinder_setting`
	/// (the *dial used for this shot*). This is the bean's own
	/// recommended dial recorded with the bag.
	val grinderSetting: String? = null,
	/// The bean's grinder NAME at the time of the shot (e.g. "Niche
	/// Zero") — so history can say which grinder pulled the shot even
	/// after the bag's grinder is edited (issue #16; the snapshot used
	/// to carry only the dial). Additive + optional, so pre-existing
	/// stored shots decode unchanged.
	val grinder: String? = null
)

/// Pre-computed summary peaks over a [`ShotRecord`]'s telemetry —
/// what the History list and detail readouts surface above the chart.
/// Returned by [`ShotRecord::peaks`] so each shell consumes the
/// identical numbers without re-deriving the formula or threshold.
/// 
/// Distinct from [`ShotMetrics`]: this struct adds the scale-derived
/// `peak_weight` / `final_weight` (which `ShotMetrics` skips because
/// they depend on a paired scale) and surfaces `peak_temp`, which
/// `ShotMetrics` doesn't track.
@Serializable
data class ShotPeaks (
	/// Peak scale weight reached during the shot, grams. `None` when
	/// no scale was paired (no sample carried a `scale_weight`).
	val peakWeight: Float? = null,
	/// Final scale weight at shot end, grams. `None` for the same
	/// reason. NOT the same as `peak_weight`: a long drip-off makes
	/// `final_weight` exceed `peak_weight` after the user pulls the
	/// cup away.
	val finalWeight: Float? = null,
	/// Peak group pressure reached, bar.
	val peakPressure: Float,
	/// Peak group-head temperature reached, °C.
	val peakTemp: Float
)

/// Everything [`analyze_shot`] needs — the port of `ShotAnalysis::analyzeShot`'s
/// parameter list (`shotanalysis.cpp:731-747`), minus the conductance
/// derivative (computed internally from pressure + flow) and the expert band
/// (omitted in this port).
@Serializable
data class ShotQualityInput (
	/// Group pressure (bar) over the shot.
	val pressure: List<SeriesPoint>,
	/// Group flow (mL/s) over the shot.
	val flow: List<SeriesPoint>,
	/// Cup weight (g) over the shot; may be empty (no scale).
	val weight: List<SeriesPoint>,
	/// Commanded pressure goal (bar); may be empty.
	val pressureGoal: List<SeriesPoint>,
	/// Commanded flow goal (mL/s); may be empty.
	val flowGoal: List<SeriesPoint>,
	/// Phase boundary markers in time order.
	val phases: List<PhaseMarker>,
	/// Beverage type; `filter` / `pourover` / `tea` / `steam` / `cleaning`
	/// (case-insensitive) skip the puck-integrity detectors.
	val beverageType: String,
	/// Total shot duration, seconds — the default pour end when no "End"
	/// marker is present.
	val durationS: Double,
	/// Configured duration of profile frame 0, seconds; `-1` when unknown.
	/// Drives the short-first-step cutoff in skip-first-frame detection.
	val firstFrameConfiguredS: Double,
	/// Effective stop-at-weight target (g); `0` disables the yield arms.
	val targetWeightG: Double,
	/// Final in-cup weight (g); `0` disables the yield arms.
	val finalWeightG: Double,
	/// Number of frames in the profile; `-1` when unknown. Values `< 2`
	/// suppress skip-first-frame detection.
	val expectedFrameCount: Int,
	/// Per-profile analysis flags: `grind_check_skip`, `channeling_expected`,
	/// `flow_trend_ok`.
	val analysisFlags: List<String>,
	/// Whether the profile's shape is known well enough to trust the flow
	/// goal as a target (Decenza: KB resolution succeeded). When false,
	/// grind Arm 1 (flow-vs-goal averaging) is skipped entirely; Arm 2's
	/// physics-level arms still run (`shotanalysis.cpp:369-384`).
	val profileKbResolved: Boolean,
	/// Per-frame exit specs from the profile snapshot, indexed by frame
	/// number; empty when no profile was stored. Lets the analysis infer
	/// the `transition_reason` shells can't supply (see [`FrameExitSpec`]).
	/// `serde(default)` — additive, absent on inputs built before it.
	val frameExits: List<FrameExitSpec>? = null
)

/// Combined output of [`analyze_shot`]: the prose lines (ending in one
/// verdict line, except on the insufficient-data early return), the badge
/// projection, the stable verdict category, and the structured detector
/// results the lines were formatted from.
@Serializable
data class ShotQualityReport (
	/// Prose observation list, verdict last.
	val lines: List<QualityLine>,
	/// Badge projection for chips.
	val badges: QualityBadges,
	/// Stable enum-like category (see `shotanalysis.h:578-599`):
	/// `clean`, `cleanGrindNotAnalyzable`, `insufficientData`,
	/// `puckTruncated`, `skipFirstFrame`, `yieldOvershoot`, `chokedPuck`,
	/// `puckIntegrity[GrindFine|GrindCoarse]`,
	/// `minorIssues[GrindFine|GrindCoarse]`.
	val verdictCategory: String,
	/// The typed detector values behind the lines.
	val detectors: DetectorResults
)

/// One decoded telemetry sample from the DE1, notified at ~4–10 Hz during a
/// shot (see protocol §3).
/// 
/// Temperatures are °C, pressure is bar, flow is ml/s. This type is `Clone` but
/// deliberately not `Copy`: it is large enough (a dozen fields) that implicit
/// copies are not a good default — pass it by reference.
@Serializable
data class ShotSample (
	/// Free-running 16-bit AC half-cycle counter; wraps at 65536 (protocol §3.3).
	val sampleTime: UShort,
	/// Measured group pressure, bar.
	val groupPressure: Float,
	/// Measured group flow, ml/s.
	val groupFlow: Float,
	/// Measured group head temperature, °C.
	val headTemp: Float,
	/// Measured mix temperature, °C.
	val mixTemp: Float,
	/// Target mix temperature, °C.
	val setMixTemp: Float,
	/// Target head temperature, °C.
	val setHeadTemp: Float,
	/// Target group pressure, bar.
	val setGroupPressure: Float,
	/// Target group flow, ml/s.
	val setGroupFlow: Float,
	/// Index of the profile frame currently executing.
	val frameNumber: UByte,
	/// Steam heater temperature, °C.
	val steamTemp: Float
)

/// A telemetry sample tagged with its time since the shot began.
/// 
/// The DE1's [`ShotSample`] is the raw protocol decode (pressure, flow,
/// temperatures, setpoints). The overlay fields below carry data that
/// rides *with* a DE1 sample but isn't on the wire:
/// 
/// - the scale's smoothed weight + flow at this instant (`scale_weight`,
/// `scale_flow_weight`) — only present when a scale was paired;
/// - the running pump-side dispensed volume (`dispensed_volume`) —
/// the DE1's integrated `group_flow × Δt`, computed core-side;
/// - the two puck-resistance signals (`resistance`,
/// `resistance_weight`) — pre-computed by [`crate::lib::puck_resistance`]
/// / `puck_resistance_weight` so every shell consumes the identical
/// value without re-deriving the formula or threshold.
/// 
/// All overlays are `Option<f32>`: legacy `.shot.json` imports
/// pre-dating this PR carry none of them, and a shot pulled without a
/// scale paired carries no `scale_*` values. `#[serde(default)]` so an
/// older record deserialises cleanly with the new fields absent.
@Serializable
data class TimedSample (
	/// Time since the shot started. Serialises as a millisecond
	/// integer (`u32`) on the wire so the JSON shape is JS-friendly
	/// — Rust keeps the internal `Duration` for arithmetic.
	val elapsed: Long,
	/// The telemetry sample.
	val sample: ShotSample,
	/// Scale-derived cumulative weight at this instant, grams. `None`
	/// when no scale was paired. Maps to the legacy de1app `espresso_weight`
	/// channel + the Visualizer `totals.weight` upload field.
	val scaleWeight: Float? = null,
	/// Scale-derived mass-flow rate at this instant, grams per second
	/// (`dW/dt`). `None` when no scale was paired. The truer espresso
	/// flow during the pour — measures what exits the puck. Maps to
	/// `espresso_flow_weight` + Visualizer `flow.by_weight`.
	val scaleFlowWeight: Float? = null,
	/// Running pump-side dispensed volume at this instant, millilitres.
	/// `None` for legacy imports that didn't record it; live captures
	/// always populate it from the DE1's integrator. Maps to
	/// `espresso_water_dispensed` + Visualizer `totals.water_dispensed`.
	val dispensedVolume: Float? = null,
	/// DE1-flow-derived puck resistance, `bar / (ml/s)²`. `None` near
	/// zero flow (the `puck_resistance` floor). NOT uploaded to
	/// Visualizer — the spec accepts no `espresso_resistance` field;
	/// Visualizer derives the same series server-side from pressure +
	/// flow. Carried on the sample only so the chart can render it
	/// without re-deriving per render pass.
	val resistance: Float? = null,
	/// Scale-flow-derived puck resistance, `bar / (g/s)²`. `None` when
	/// no scale was paired or scale flow is sub-floor. The chart prefers
	/// this over `resistance` per-sample when present. Same
	/// non-upload story as `resistance`.
	val resistanceWeight: Float? = null
)

/// The user's Visualizer sync **preferences** — the portable, cross-shell
/// subset a whole-app backup carries. One shared `#[typeshare]` shape so web
/// and Android serialise byte-identical JSON: a backup's `visualizerPrefs`
/// line restores on either shell (no per-shell tag), and the two devices can
/// converge on one set of choices.
/// 
/// NOT here: OAuth tokens, the cached account, the in-flight PKCE handshake,
/// pull cursors, the premium-tier cache, last-sync timestamps, and the sync
/// activity log — those are per-device runtime state, kept shell-local and
/// never backed up.
/// 
/// Two distinct auto gates (the web shell has both; Android today only honours
/// `auto_upload`):
/// - `auto_upload` — auto-push a shot to Visualizer as it completes.
/// - `auto_sync` — fire background library (bean/roaster/shot) pushes on
/// mutation; manual "Sync now" always works regardless.
/// 
/// `#[serde(default)]` on the whole struct (via [`Default`]) so a partial blob
/// deserialises to the canonical defaults rather than failing — a shell that
/// doesn't own a field (Android doesn't drive `beans_direction`) round-trips it
/// untouched, and an older/partial line fills gaps from the defaults below.
@Serializable
data class VisualizerSyncPrefs (
	/// Auto-push a finished shot to Visualizer (web `visualizerAutoUpload`;
	/// Android's single auto gate). Default: true.
	val autoUpload: Boolean,
	/// Fire background bean/roaster/shot pushes on mutation (web sync-config
	/// `autoSync`). Android doesn't background-sync the library yet, so it
	/// carries the field but doesn't act on it. Default: true.
	val autoSync: Boolean,
	/// Upload privacy: `"public" | "unlisted" | "private"`. Default: unlisted.
	val privacy: String,
	/// Include the profile block in uploads. Default: true.
	val includeProfile: Boolean,
	/// Include tasting notes in uploads. Default: false.
	val includeNotes: Boolean,
	/// Shots sync direction: `"off" | "backup" | "pull" | "two-way"`. Default: backup.
	val shotsDirection: String,
	/// Beans sync direction. Web-driven; Android carries the default only. Default: two-way.
	val beansDirection: String,
	/// Roasters sync direction. Web-driven; Android carries the default only. Default: two-way.
	val roastersDirection: String
)

/// The fields the planner reads from a remote shot row. Visualizer's
/// API returns a superset; we only care about identity + the de-dup
/// hash inputs + editable annotations. Mirrors the TS `WireShot` in
/// `shot-sync-signatures.ts`. Unix MS (converted at the spec boundary
/// from the spec's unix-sec `clock` / `updated_at`).
/// 
/// `#[serde(default)]` on the optional fields so a shell that omits them
/// deserialises cleanly. The wasm / FFI bridges JSON-marshal this.
@Serializable
data class WireShot (
	/// Visualizer shot id — the remote primary key.
	val id: String,
	/// Shot start timestamp, unix MS (converted from spec's unix-sec `clock`).
	val clock: Long,
	/// Total shot duration, milliseconds.
	val duration_ms: Long,
	/// Display name of the profile pulled.
	val profile_title: String? = null,
	/// Final scale weight at shot end (grams), or `None`.
	val final_weight_g: Float? = null,
	/// Annotations the user has typed remotely.
	val notes: String? = null,
	/// Star rating (0..5), or `None`.
	val rating: Int? = null,
	/// Last server-side update, unix MS (from spec's unix-sec
	/// `updated_at`). Drives LWW conflict resolution.
	val updated_at_ms: Long? = null,
	/// Shot-level tags pulled from the remote — the `tags` array on
	/// `DefaultShotDetail` (Visualizer's native serializer; the
	/// Beanconqueror variant doesn't carry shot tags). These are
	/// mutable metadata, NOT part of the de-dup signature: a remote
	/// re-tagging doesn't change the shot's identity.
	/// 
	/// `#[serde(default)]` so older shells / responses without the
	/// field still deserialise cleanly to an empty Vec.
	val tag_list: List<String>? = null
)

/// What kind of beverage a profile produces. Mirrors reaprime's
/// `BeverageType` enum and the community v2 JSON contract's
/// `beverage_type` field. Defaults to `Espresso` on import — both
/// reaprime and Crema fall back lenient here (not strict) because the
/// field is metadata, not execution.
@Serializable
enum class BeverageType(val string: String) {
	/// Standard espresso shot. The default for absent / unknown values.
	@SerialName("espresso")
	Espresso("espresso"),
	/// A calibration routine (flow / pressure cal profiles).
	@SerialName("calibrate")
	Calibrate("calibrate"),
	/// A cleaning / backflush routine.
	@SerialName("cleaning")
	Cleaning("cleaning"),
	/// Hand-controlled (manual) profile — the firmware honours user
	/// adjustments mid-shot.
	@SerialName("manual")
	Manual("manual"),
	/// Pour-over style profile (long, low-pressure).
	@SerialName("pourover")
	Pourover("pourover"),
}

/// What a calibration packet asks the DE1 to do.
/// 
/// `#[non_exhaustive]` so any future firmware-side calibration verb can
/// land here without breaking the FFI surface — this enum is the payload
/// of `Event::Calibration` alongside `CalTarget`.
@Serializable
enum class CalCommand(val string: String) {
	/// Read the calibration currently in use.
	@SerialName("ReadCurrent")
	ReadCurrent("ReadCurrent"),
	/// Write a new calibration.
	@SerialName("Write")
	Write("Write"),
	/// Reset the sensor to its factory calibration.
	@SerialName("ResetToFactory")
	ResetToFactory("ResetToFactory"),
	/// Read the factory calibration.
	@SerialName("ReadFactory")
	ReadFactory("ReadFactory"),
}

/// Which sensor a calibration applies to.
@Serializable
enum class CalTarget(val string: String) {
	/// The flow-rate sensor.
	@SerialName("Flow")
	Flow("Flow"),
	/// The pressure sensor.
	@SerialName("Pressure")
	Pressure("Pressure"),
	/// The temperature sensor.
	@SerialName("Temperature")
	Temperature("Temperature"),
}

/// The direction of an exit comparison. Lowercase wire spelling
/// (`"over"` / `"under"`) per the v2 contract.
@Serializable
enum class Compare(val string: String) {
	/// Exit when the metric rises above the threshold.
	@SerialName("over")
	Over("over"),
	/// Exit when the metric falls below the threshold.
	@SerialName("under")
	Under("under"),
}

/// The metric an exit condition watches. Lowercase wire spelling
/// (`"pressure"` / `"flow"`) per the v2 contract.
@Serializable
enum class ExitMetric(val string: String) {
	/// Watch pressure (bar).
	@SerialName("pressure")
	Pressure("pressure"),
	/// Watch flow (ml/s).
	@SerialName("flow")
	Flow("flow"),
}

/// Generated type representing the anonymous struct variant `UpToDate` of the `FirmwareUpdateStatus` Rust enum
@Serializable
data class FirmwareUpdateStatusUpToDateInner (
	/// The installed build number.
	val installed: UShort
)

/// Generated type representing the anonymous struct variant `UpdateAvailable` of the `FirmwareUpdateStatus` Rust enum
@Serializable
data class FirmwareUpdateStatusUpdateAvailableInner (
	/// The installed build number.
	val installed: UShort,
	/// The latest build Crema knows about.
	val latest: UShort
)

/// Generated type representing the anonymous struct variant `NewerInstalled` of the `FirmwareUpdateStatus` Rust enum
@Serializable
data class FirmwareUpdateStatusNewerInstalledInner (
	/// The installed build number.
	val installed: UShort,
	/// The (older) build Crema knows about.
	val latest: UShort
)

/// What the firmware-update check found.
/// 
/// `#[non_exhaustive]` so we can grow the enum (e.g. a future "checking…" /
/// "fetched-from-manifest" variant) without breaking shell `match`es.
@Serializable
sealed class FirmwareUpdateStatus {
	/// No DE1 connected, or MMR register `0x800010` (FirmwareVersion) has not
	/// yet been read. The shell should render "Connect a DE1 to check" or
	/// similar.
	@Serializable
	@SerialName("Unknown")
	object Unknown: FirmwareUpdateStatus()
	/// The installed build matches [`LATEST_KNOWN_FIRMWARE_BUILD`].
	@Serializable
	@SerialName("UpToDate")
	data class UpToDate(val content: FirmwareUpdateStatusUpToDateInner): FirmwareUpdateStatus()
	/// The installed build is older than [`LATEST_KNOWN_FIRMWARE_BUILD`].
	@Serializable
	@SerialName("UpdateAvailable")
	data class UpdateAvailable(val content: FirmwareUpdateStatusUpdateAvailableInner): FirmwareUpdateStatus()
	/// The installed build is newer than [`LATEST_KNOWN_FIRMWARE_BUILD`] —
	/// likely the user updated through the legacy de1app since this Crema
	/// build shipped. Informational; no action needed.
	@Serializable
	@SerialName("NewerInstalled")
	data class NewerInstalled(val content: FirmwareUpdateStatusNewerInstalledInner): FirmwareUpdateStatus()
}

