/// Known MMR register addresses.
/// 
/// This covers the registers Crema reads or writes.
/// [`address`](Self::address) gives the raw 24-bit address to pass to
/// [`read_request`] / [`write_request`].
@Serializable
enum class MmrRegister(val string: String) {
	/// CPU-board revision, encoded `cpu_board_version × 1000` (e.g. raw
	/// `1100` → PCB v1.1, raw `1300` → PCB v1.3). Read at connect time
	/// in the legacy de1app via `get_3_mmr_cpuboard_machinemodel_firmwareversion`.
	@SerialName("CpuBoardVersion")
	CpuBoardVersion("CpuBoardVersion"),
	/// Machine model identifier — `0 = Unset / unknown`, `1 = DE1`,
	/// `2 = DE1+`, `3 = DE1PRO`, `4 = DE1XL`, `5 = DE1CAFE`, `6 = DE1XXL`,
	/// `7 = DE1XXXL`. The legacy app uses this to gate model-specific
	/// settings (e.g. the cup-warmer surface on Bengle hardware).
	@SerialName("MachineModel")
	MachineModel("MachineModel"),
	/// Firmware build number.
	@SerialName("FirmwareVersion")
	FirmwareVersion("FirmwareVersion"),
	/// Group Head Controller info bitmask (bit 0: present, bit 1: active).
	@SerialName("GhcInfo")
	GhcInfo("GhcInfo"),
	/// Tank desired water-temperature threshold, °C.
	@SerialName("TankTempThreshold")
	TankTempThreshold("TankTempThreshold"),
	/// Fan-on temperature threshold, °C.
	@SerialName("FanThreshold")
	FanThreshold("FanThreshold"),
	/// Machine serial number.
	@SerialName("SerialNumber")
	SerialNumber("SerialNumber"),
	/// Steam flow rate.
	@SerialName("SteamFlow")
	SteamFlow("SteamFlow"),
	/// Refill-kit presence.
	@SerialName("RefillKit")
	RefillKit("RefillKit"),
	/// Flush flow rate.
	@SerialName("FlushFlowRate")
	FlushFlowRate("FlushFlowRate"),
	/// Flush water target temperature, °C — the temperature the DE1
	/// holds while a group-flush cycle runs. Wire value is `°C × 10`
	/// (so 950 = 95.0 °C). Modelled by reaprime
	/// (`de1.models.dart:flushTemp` at `0x00803844`, 4-byte slot,
	/// `readScale: 0.1`); the legacy de1app TCL has no equivalent.
	@SerialName("FlushTemp")
	FlushTemp("FlushTemp"),
	/// Hot-water flow rate.
	@SerialName("HotWaterFlowRate")
	HotWaterFlowRate("HotWaterFlowRate"),
	/// Hot-water dispense phase-1 flow rate.
	@SerialName("Phase1FlowRate")
	Phase1FlowRate("Phase1FlowRate"),
	/// Hot-water dispense phase-2 flow rate.
	@SerialName("Phase2FlowRate")
	Phase2FlowRate("Phase2FlowRate"),
	/// Hot-water idle temperature, °C.
	@SerialName("HotWaterIdleTemp")
	HotWaterIdleTemp("HotWaterIdleTemp"),
	/// Group head control mode.
	@SerialName("GhcMode")
	GhcMode("GhcMode"),
	/// Seconds of high-flow steam at the start of a steam cycle.
	@SerialName("SteamHighFlowStart")
	SteamHighFlowStart("SteamHighFlowStart"),
	/// Mains heater voltage.
	@SerialName("HeaterVoltage")
	HeaterVoltage("HeaterVoltage"),
	/// "HeaterUp Phase 2 Timeout" — the firmware/spec name (reaprime
	/// `heaterUp2Timeout`, MMR `0x803838`, ×10 deciseconds). de1app calls the
	/// user-facing *setting* `espresso_warmup_timeout` (written inline in
	/// `set_heater_tweaks`); crema's setter keeps that de1app name, but the
	/// register itself is named after the firmware here (audit F9).
	@SerialName("HeaterUp2Timeout")
	HeaterUp2Timeout("HeaterUp2Timeout"),
	/// Calibration flow multiplier (`int(1000 * multiplier)`).
	@SerialName("CalibrationFlowMultiplier")
	CalibrationFlowMultiplier("CalibrationFlowMultiplier"),
	/// Flush timeout (`int(10 * seconds)`).
	@SerialName("FlushTimeout")
	FlushTimeout("FlushTimeout"),
	/// USB charger on (1 = tablet USB charging enabled).
	@SerialName("UsbChargerOn")
	UsbChargerOn("UsbChargerOn"),
	/// Feature-flag bitmask (e.g. the `UserNotPresent` flag).
	@SerialName("FeatureFlags")
	FeatureFlags("FeatureFlags"),
	/// Whether the user is currently present at the machine. The legacy app
	/// writes `1` when the user touches the screen so the firmware does not
	/// sleep on inactivity. **Distinct register from [`FeatureFlags`]** — the
	/// legacy `de1_comms.tcl` writes to two separate addresses; the firmware
	/// MMR map is not openly published but the legacy source treats them as
	/// unrelated registers.
	@SerialName("UserPresent")
	UserPresent("UserPresent"),
	/// Steam two-tap stop register — the second `tap` of the
	/// double-tap-to-stop steam UX (`heater_tweaks`).
	@SerialName("SteamTwoTapStop")
	SteamTwoTapStop("SteamTwoTapStop"),
	/// Cup-warmer temperature (Bengle models only).
	@SerialName("CupWarmerTemp")
	CupWarmerTemp("CupWarmerTemp"),
}

/// Generated type representing the anonymous struct variant `TooManySteps` of the `ProfileUploadFailure` Rust enum
@Serializable
data class ProfileUploadFailureTooManyStepsInner (
	/// How many steps the rejected profile had.
	val count: UInt
)

/// Generated type representing the anonymous struct variant `UnexpectedAck` of the `ProfileUploadFailure` Rust enum
@Serializable
data class ProfileUploadFailureUnexpectedAckInner (
	/// The `FrameToWrite` byte the core expected next, raw (`≥ 32` for
	/// an expected extension ack, `== frame_count` for the tail).
	val expected: UByte,
	/// The `FrameToWrite` byte the ack actually carried.
	val got: UByte
)

/// Generated type representing the anonymous struct variant `AckTimeout` of the `ProfileUploadFailure` Rust enum
@Serializable
data class ProfileUploadFailureAckTimeoutInner (
	/// The `FrameToWrite` byte the core was waiting for when the
	/// timeout fired.
	val awaiting: UByte
)

/// Generated type representing the anonymous struct variant `Internal` of the `ProfileUploadFailure` Rust enum
@Serializable
data class ProfileUploadFailureInternalInner (
	/// Human-readable `Display` of the underlying error.
	val message: String
)

/// Why a profile upload failed.
/// 
/// `#[non_exhaustive]` so additional categories (e.g. a firmware-side
/// "shot in progress" rejection signalled through some future cuuid_10
/// packet) can be added without breaking the FFI surface.
@Serializable
sealed class ProfileUploadFailure {
	/// The profile had no steps.
	@Serializable
	@SerialName("Empty")
	object Empty: ProfileUploadFailure()
	/// The profile had more than 32 steps.
	@Serializable
	@SerialName("TooManySteps")
	data class TooManySteps(val details: ProfileUploadFailureTooManyStepsInner): ProfileUploadFailure()
	/// A frame ack arrived for a frame number the orchestrator did not
	/// expect — either out-of-order or for a step the profile does not have.
	@Serializable
	@SerialName("UnexpectedAck")
	data class UnexpectedAck(val details: ProfileUploadFailureUnexpectedAckInner): ProfileUploadFailure()
	/// No ack arrived within
	/// [`PROFILE_UPLOAD_ACK_TIMEOUT`](crate::PROFILE_UPLOAD_ACK_TIMEOUT) of
	/// the most recent ack (or upload start, for the first ack).
	@Serializable
	@SerialName("AckTimeout")
	data class AckTimeout(val details: ProfileUploadFailureAckTimeoutInner): ProfileUploadFailure()
	/// The shell called
	/// [`cancel_profile_upload`](crate::CremaCore::cancel_profile_upload)
	/// mid-upload.
	@Serializable
	@SerialName("Aborted")
	object Aborted: ProfileUploadFailure()
	/// An unexpected [`AppError`] variant — the bridge couldn't classify it.
	/// The `message` carries the `AppError`'s `Display` output so the shell
	/// can surface it in a toast / log without losing the underlying cause.
	/// 
	/// Previously such variants were silently coerced to
	/// [`ProfileUploadFailure::Empty`], misclassifying real failures.
	@Serializable
	@SerialName("Internal")
	data class Internal(val details: ProfileUploadFailureInternalInner): ProfileUploadFailure()
}

/// Which quantity a step holds at its target. Serializes as lowercase
/// (`"pressure"` / `"flow"`) to match the community v2 JSON contract.
@Serializable
enum class Pump(val string: String) {
	/// Pressure priority — the step targets a pressure in bar.
	@SerialName("pressure")
	Pressure("pressure"),
	/// Flow priority — the step targets a flow rate in ml/s.
	@SerialName("flow")
	Flow("flow"),
}

/// What the shell should do with a just-completed shot — decided at the
/// core boundary so both shells classify identically (previously each
/// re-implemented the aborted rule and the cleaning-profile lookup).
/// 
/// The *mechanics* stay shell-side: `DiscardAborted` is held behind an
/// undo toast (live side effects — bean debit, webhook — still run,
/// because the dose was physically ground); `SkipCleaning` records
/// nothing at all (nothing was ground — machine maintenance runs in the
/// DE1's Espresso state, so a cleaning/backflush profile would otherwise
/// be recorded as a shot; Decenza #1325, `maincontroller.cpp:1841-1853`).
@Serializable
enum class ShotDisposition(val string: String) {
	/// A real shot — persist the history row, sync, capture.
	@SerialName("Record")
	Record("Record"),
	/// An aborted pull (short AND light) — discard behind an undo.
	@SerialName("DiscardAborted")
	DiscardAborted("DiscardAborted"),
	/// A cleaning/backflush run — record nothing.
	@SerialName("SkipCleaning")
	SkipCleaning("SkipCleaning"),
}

