/// Which temperature a step regulates. Variant names match the community
/// v2 JSON contract used by the legacy de1app TCL + reaprime. The enum
/// describes "what the step's temperature target represents," not which
/// sensor it reads:
/// - `Coffee` — regulate temperature of the coffee at the basket; the
/// firmware holds `head_temp` to the step's target.
/// - `Water` — regulate temperature of the water exiting the group; the
/// firmware holds `mix_temp` to the step's target. Flips the
/// wire-format `target_mix_temp` flag bit on each frame.
@Serializable
enum class TempSensor(val string: String) {
	/// Regulate temperature of the coffee at the basket.
	@SerialName("coffee")
	Coffee("coffee"),
	/// Regulate temperature of the water exiting the group.
	@SerialName("water")
	Water("water"),
}

/// How a step moves to its target value. Serializes as lowercase
/// `"fast"` / `"smooth"` to match the community v2 profile JSON contract
/// shared with the legacy de1app TCL and reaprime.
@Serializable
enum class Transition(val string: String) {
	/// Jump straight to the target.
	@SerialName("fast")
	Fast("fast"),
	/// Ramp smoothly to the target.
	@SerialName("smooth")
	Smooth("smooth"),
}

/// Which kind of water-dispensing session the DE1 is running.
/// 
/// `#[non_exhaustive]` so additional session kinds (e.g. a future `SteamRinse`
/// classification) can be added without breaking the FFI surface — this enum
/// rides on every `WaterEvent::Started` payload.
@Serializable
enum class WaterSessionKind(val string: String) {
	/// A hot-water pour (DE1 `HotWater` state).
	@SerialName("HotWater")
	HotWater("HotWater"),
	/// A group-head flush / rinse (DE1 `HotWaterRinse` state).
	@SerialName("Flush")
	Flush("Flush"),
}

/// The user's chosen *display unit* for weight.
/// 
/// Canonical storage is always grams; this enum names the unit the shell
/// surfaces — and crucially, the unit the Decent Scale's on-scale LCD must
/// be told to render. The Decent Scale exposes two LCD-enable wire packets
/// (one with byte `[4] = 0x00` for grams, one with byte `[4] = 0x01` for
/// ounces); the core picks the right packet based on this enum so the
/// on-scale display matches the shell.
/// 
/// `#[typeshare]` + serde: the web shell already keeps a TypeScript
/// `WeightUnit` (`'g' | 'oz'`) in its settings store; carrying the same
/// shape through the bridge means the shell can pass its existing pref
/// straight through without a lookup table.
@Serializable
enum class WeightUnit(val string: String) {
	/// Grams — the canonical unit and the Decent Scale's default LCD mode.
	@SerialName("grams")
	Grams("grams"),
	/// US avoirdupois ounces — the only imperial display alternative.
	@SerialName("ounces")
	Ounces("ounces"),
}

/// A writable DE1 GATT characteristic. The shell maps this to a UUID.
/// 
/// `#[non_exhaustive]`: profile-upload targets arrive later.
@Serializable
enum class WriteTarget(val string: String) {
	/// The DE1 `RequestedState` characteristic (`cuuid_02`).
	@SerialName("De1RequestedState")
	De1RequestedState("De1RequestedState"),
	/// The DE1 steam / hot-water `ShotSettings` characteristic (`cuuid_0B`).
	@SerialName("De1ShotSettings")
	De1ShotSettings("De1ShotSettings"),
	/// The DE1 `ReadFromMMR` characteristic (`cuuid_05`) — an MMR read request
	/// is *written* here; the DE1 answers on the same characteristic's notify.
	@SerialName("De1MmrRequest")
	De1MmrRequest("De1MmrRequest"),
	/// The DE1 `WriteToMMR` characteristic (`cuuid_06`) — an MMR write packet
	/// is sent here. Sibling of [`De1MmrRequest`] on the read side; the two
	/// use distinct UUIDs even though they share a packet layout.
	@SerialName("De1MmrWrite")
	De1MmrWrite("De1MmrWrite"),
	/// The DE1 `Calibration` characteristic (`cuuid_12`) — a calibration read
	/// request is *written* here; the DE1 answers on the same characteristic.
	@SerialName("De1Calibration")
	De1Calibration("De1Calibration"),
	/// The DE1 `WaterLevels` characteristic (`cuuid_11`) — the same
	/// characteristic the DE1 notifies tank level on; a 4-byte
	/// `WaterLevels` packet is *written* here to set the refill threshold.
	@SerialName("De1WaterLevels")
	De1WaterLevels("De1WaterLevels"),
	/// The DE1 `HeaderWrite` characteristic (`cuuid_0F`) — the 5-byte
	/// `ShotHeader` packet is *written* here at the start of a profile
	/// upload.
	@SerialName("De1ProfileHeader")
	De1ProfileHeader("De1ProfileHeader"),
	/// The DE1 `FrameWrite` characteristic (`cuuid_10`) — each 8-byte
	/// frame packet (normal frames, extension frames, and the tail) is
	/// *written* here in upload order during a profile upload. The DE1
	/// echoes each write back as a `Source::De1FrameAck` notification.
	@SerialName("De1ProfileFrame")
	De1ProfileFrame("De1ProfileFrame"),
}

